#### 控制器
创建一个控制器来处理文件上传和 JSON 数据解析。

```java
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;
import com.fasterxml.jackson.databind.ObjectMapper;

import java.io.IOException;
import java.util.List;

@RestController
@RequestMapping("/upload")
public class UploadController {

    private final ObjectMapper objectMapper;

    public UploadController(ObjectMapper objectMapper) {
        this.objectMapper = objectMapper;
    }

    @PostMapping
    public ResponseEntity<String> handleFileUpload(
            @RequestParam("listObject") String listObjectJson,
            @RequestParam("file") MultipartFile file) {

        try {
            // 解析 JSON 数据
            List<ReadUploadParam> listObject = objectMapper.readValue(listObjectJson,
                    objectMapper.getTypeFactory().constructCollectionType(List.class, ReadUploadParam.class));

            // 处理文件
            String fileName = file.getOriginalFilename();
            // 你可以在这里保存文件或进行其他处理

            // 打印解析后的数据
            System.out.println("List Object: " + listObject);
            System.out.println("File: " + fileName);

            return ResponseEntity.ok("Upload successful");
        } catch (IOException e) {
            e.printStackTrace();
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body("Upload failed");
        }
    }

    // 定义 ReadUploadParam 类
    public static class ReadUploadParam {
        private String dsName;
        private String dsVersion;
        private String aliasFileName;
        private String tabName;

        // Getters and Setters
        public String getDsName() {
            return dsName;
        }

        public void setDsName(String dsName) {
            this.dsName = dsName;
        }

        public String getDsVersion() {
            return dsVersion;
        }

        public void setDsVersion(String dsVersion) {
            this.dsVersion = dsVersion;
        }

        public String getAliasFileName() {
            return aliasFileName;
        }

        public void setAliasFileName(String aliasFileName) {
            this.aliasFileName = aliasFileName;
        }

        public String getTabName() {
            return tabName;
        }

        public void setTabName(String tabName) {
            this.tabName = tabName;
        }

        @Override
        public String toString() {
            return "ReadUploadParam{" +
                    "dsName='" + dsName + '\'' +
                    ", dsVersion='" + dsVersion + '\'' +
                    ", aliasFileName='" + aliasFileName + '\'' +
                    ", tabName='" + tabName + '\'' +
                    '}';
        }
    }
}
```

### 总结
通过以上步骤，你可以在 Angular 中同时发送包含列表对象的 JSON 数据和包含文件的 `FormData` 数据，并在 Spring Boot 服务器端正确解析和处理这些数据。确保前端和后端的数据格式和字段名称一致，以便顺利完成数据传输和解析。
